-- DCS ATC Bot — Operational Configuration
-- DO NOT EDIT THIS FILE for your personal settings.
-- Instead, create a file called config.local.lua in the same folder
-- and put your overrides there. config.local.lua is gitignored, so
-- git pull will never conflict with your settings.
--
-- Example config.local.lua:
--   AIRPORT_ICAO  = "LCRA"
--   ATC_CALLSIGN  = "Akrotiri"
--   FREQ_APPROACH = 119000000
--   FREQ_TOWER    = 119500000
--   FREQ_GROUND   = 118000000
--
-- Any value set in config.local.lua overrides the same value here.
-- Restart the bot after making changes.

